#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define REC_LENGTH 49
#define MAX_RECORDS 2000000

typedef struct latLong {
    float lat;
    float lng;
} LatLong;

typedef struct record {
    char recString[REC_LENGTH];
    float distance;
} Record;

char *data_folder = NULL;

void findLowest(Record *records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int loadData(char *filename, Record *records, LatLong *locations, int maxRecords) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[256], db_fullname[512];
    int recNum = 0;

    if (data_folder == NULL) {
        data_folder = getenv("DATA_FOLDER");
        if (data_folder == NULL) {
            data_folder = ".";
        }
    }

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening filelist: %s\n", filename);
        return 0;
    }

    while (!feof(flist) && recNum < maxRecords) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            break;
        }
        // Remove potential trailing newline or whitespace from dbname if fscanf didn't handle it perfectly
        dbname[strcspn(dbname, "\n\r")] = 0;

        snprintf(db_fullname, sizeof(db_fullname), "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            fprintf(stderr, "error opening a db (%s)\n", db_fullname);
            fclose(flist);
            return recNum;
        }

        while (!feof(fp) && recNum < maxRecords) {
            Record record;
            LatLong latLong;

            // Read line
            if (fgets(record.recString, REC_LENGTH, fp) == NULL) break;

            // Check if line is valid (contains data)
            if (strlen(record.recString) < 38) { 
                // Ensure we have enough chars for the substrings we extract later
                continue; 
            }

            char substr[6];

            // Extract latitude (chars 28-32)
            for(i=0; i<5; i++) {
                if (28+i < strlen(record.recString))
                    substr[i] = record.recString[28+i];
                else
                    substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            // Extract longitude (chars 33-37)
            for(i=0; i<5; i++) {
                if (33+i < strlen(record.recString))
                    substr[i] = record.recString[33+i];
                else
                    substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations[recNum] = latLong;
            records[recNum] = record;
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 256);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    if (i < argc) *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (i+1 < argc) {
                        if (argv[i][2] == 'a') {
                            *lat = atof(argv[i + 1]);
                        } else {
                            *lng = atof(argv[i + 1]);
                        }
                        i++;
                    }
                    break;
                case 'h':
                    return 1;
                    break;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    if (i < argc) *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    if (i < argc) *d = atoi(argv[i]);
                    break;
                case 'f':
                    i++;
                    if (i < argc) data_folder = argv[i];
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

float *OpenMPFindNearestNeighbors(
    int numRecords,
    LatLong *locations,
    float lat,
    float lng,
    int timing) {

    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(1);
    }

    double start_time = 0.0, end_time = 0.0;
    if (timing) {
        start_time = omp_get_wtime();
    }

    #pragma omp parallel for
    for (int i = 0; i < numRecords; i++) {
        float diff_lat = lat - locations[i].lat;
        float diff_lng = lng - locations[i].lng;
        distances[i] = sqrt(diff_lat * diff_lat + diff_lng * diff_lng);
    }

    if (timing) {
        end_time = omp_get_wtime();
        printf("Kernel Execution Time: %f seconds\n", end_time - start_time);
    }

    return distances;
}

int main(int argc, char *argv[]) {
    Record *records = NULL;
    LatLong *locations = NULL;
    float *recordDistances = NULL;
    int i;

    char filename[256];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;
    int numRecords = 0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    // Allocate buffers
    records = (Record *)malloc(sizeof(Record) * MAX_RECORDS);
    locations = (LatLong *)malloc(sizeof(LatLong) * MAX_RECORDS);

    if (!records || !locations) {
        fprintf(stderr, "Memory allocation failed\n");
        if (records) free(records);
        if (locations) free(locations);
        exit(1);
    }

    numRecords = loadData(filename, records, locations, MAX_RECORDS);

    if (numRecords == 0) {
        fprintf(stderr, "No records loaded. Check input files.\n");
        free(records);
        free(locations);
        exit(1);
    }

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    double total_start = 0.0, total_end = 0.0;
    if (timing) {
        total_start = omp_get_wtime();
    }

    recordDistances = OpenMPFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet) {
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }
    }

    if (timing) {
        total_end = omp_get_wtime();
        printf("Total Time: %f seconds\n", total_end - total_start);
    }

    free(recordDistances);
    free(records);
    free(locations);
    return 0;
}
